from itertools import combinations
def rank2_plucker(vals, n):
    # vals dict pair tuple sorted -> 0/1/int
    for quad in combinations(range(n),4):
        a,b,c,d=quad
        sums=[vals[tuple(sorted(x))]+vals[tuple(sorted(y))] for x,y in [((a,b),(c,d)),((a,c),(b,d)),((a,d),(b,c))]]
        m=min(sums)
        if sums.count(m)<2:
            return False
    return True
n=6
pairs=list(combinations(range(n),2))
p_list=[]
for mask in range(1<<len(pairs)):
    vals={pairs[i]:(mask>>i)&1 for i in range(len(pairs))}
    if rank2_plucker(vals,n):
